    ```typescript
    class Node {
        constructor(public key: string, public value: number) {
            this.prev = null;
            this.next = null;
        }
    }

    class LRUCache {
        private map = new Map<string, Node>();
        private head = new Node("", 0);
        private tail = new Node("", 0);
        constructor(private capacity: number) {
            this.head.next = this.tail;
            this.tail.prev = this.head;
        }

        private remove(node: Node) {
            node.prev!.next = node.next;
            node.next!.prev = node.prev;
        }

        private addToHead(node: Node) {
            node.next = this.head.next;
            node.prev = this.head;
            this.head.next!.prev = node;
            this.head.next = node;
        }

        put(key: string, value: number) {
            if (this.map.has(key)) {
                const node = this.map.get(key)!;
                node.value = value;
                this.remove(node);
                this.addToHead(node);
            } else {
                if (this.map.size === this.capacity) {
                    const lru = this.tail.prev!;
                    this.remove(lru);
                    this.map.delete(lru.key);
                }
                const newNode = new Node(key, value);
                this.addToHead(newNode);
                this.map.set(key, newNode);
            }
        }

        get(key: string): number {
            if (this.map.has(key)) {
                const node = this.map.get(key)!;
                this.remove(node);
                this.addToHead(node);
                return node.value;
            }
            return -1;
        }

        del(key: string) {
            if (this.map.has(key))) {
                const node = this.map.get(key)!;
                this.remove(node);
                this.map.delete(key);
            }
        }

        getKeys(): string[] {
            const keys: string[] = [];
             let curr = this.head.next;
             while (curr !== this.tail) {
                keys.push(curr.key);
                curr = curr.next!;
            }
            return keys;
        }
    }
    ```

